var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......그래서 뒷일은 어떻게 됐죠?","JPN":"……それで、その後はどうなったんですか？","ENG":"So what happened afterwards?","TWN":"……所以，後來怎麼樣了？"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응, 나이엘은 한 달 동안 근신 및 봉사활동 처분이래.","JPN":"ナイエルは1ヶ月の謹慎と校内奉仕の処分だって。","ENG":"Well, Naielle has been grounded and has to do volunteer service for a month.","TWN":"嗯，處分的結果是奈爾被禁足一個月，還要進行志願活動。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고 미카는 공로를 인정받아서 마술 대공연을 펼칠 행사 예산을 지원 받기로 했고.","JPN":"そしてミカは貢献を認められてマジックショーの開催費用を援助してもらうことになったんだけど。","ENG":"As for Mika, she earned recognition for her valor and secured funding for an upcoming magic show.","TWN":"還有米卡的功勞被認可，得到了魔術公演的活動預算支援。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......나이엘한테 걸었던 최면이 안 풀려서 풀릴 때까지 걔랑 봉사활동 다니게 됐지만.","JPN":"……ナイエルにかけた催眠がまだ解けてないから、校内奉仕にも同行することになったらしい。","ENG":"Although she ended up having to accompany Naielle till her hypnosis can wear off.","TWN":"……不過因為對奈爾的催眠無法解除，所以還得繼續研究怎麼改良。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"차림새랑 다르게 학생회장이 일처리가 엄청 빠르더라.","JPN":"生徒会長の仕事ぶりが思っていた以上に速くてびっくりだよ｡","ENG":"The Student President really gets things done quickly, despite her choice of clothing.","TWN":"不同於她的著裝，辦事效率非常高。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그렇군요.","JPN":"ハハハ……そうなんですね。","ENG":"Hah hah, I see.","TWN":"哈哈，原來如此。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런데 그 정도 대형 사고를 쳤는데 겨우 한 달 근신으로 끝나나요?","JPN":"それにしてもあんな大事件を起こしたのに､たった1ヶ月の謹慎で済むんですか？","ENG":"But will one month of detention be enough to address such a serious offense?","TWN":"可是這次奈爾闖了這麼大的禍，只禁足一個月嗎？"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"퇴학 처분을 받아도 이상하지 않을 것 같은데.","JPN":"退学処分を受けてもおかしくないと思いましたが。","ENG":"You'd think she could be expelled for that sort of thing.","TWN":"就算被退學我也不會感到奇怪。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......내가 처벌을 줄여 달라고 징계위원회에 부탁했어.","JPN":"……私が処分を軽くしてほしいと、懲戒委員会に頼んだよ。","ENG":"Well... I asked the disciplinary board for leniency.","TWN":"……是因為我向懲戒委員會請求對她從輕處理。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네? 정말인가요?","JPN":"え？　本当ですか？","ENG":"Huh? Really?","TWN":"啊？真的嗎？"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양은 직접적인 피해자잖아요. 그런데 왜?","JPN":"ミナさんが一番の被害者なのに、なぜ？","ENG":"But you're one of the victims, Mina. Why did you do that?","TWN":"米娜可是直接受害人呢。為什麼？"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 본인도 반성하고 있는 모양이고......","JPN":"まぁ、本人も反省しているようだし……","ENG":"Well, she seems sorry about what she did...","TWN":"嗯，因為我看到她本人也有在反省……"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"퇴각할 때 미카와 레이 선배를 위해 싸워 주기도 했으니까.","JPN":"退却する時、ミカとレイ先輩のために一応戦ってくれたからね。","ENG":"And she fought to protect Mika and Ray when they retreated.","TWN":"撤退的時候也為了米卡和雷伊前輩戰鬥過。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 왜 그렇게 쳐다 봐?","JPN":"な、なによ！　なんなの、その目は？","ENG":"W-what? Why are you staring at me like that?","TWN":"怎麼了？為什麼這麼看著我？"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아닙니다. 전 또 나이엘 양의 저축을 탈탈 털었다거나 하는 이유였나 했거든요.","JPN":"何でもないですよ。てっきりナイエルさんと裏でお金の交渉でもしたのかなと思っていたので。","ENG":"Never mind. I thought you might have gotten Naielle to pay you everything she's got or something.","TWN":"沒什麼。我想說是不是你已經洗劫了奈爾的全部財產。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"서윤 양이 들으면 섭섭해 하시겠네요.","JPN":"シズカさんが聞いたら残念がる理由でしたね。","ENG":"Seo Yoon will feel cheated if she hears about this.","TWN":"徐芸知道了會不高興吧。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그 때 이야기는 좀 하지 말라니까!","JPN":"あ、あの時の話はもういいって！","ENG":"C-can you stop talking about that?","TWN":"能不能不再提那時候的事情了！"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그런데...... 그 레이 선배라는 분은 아직 연락이 안 되나요?","JPN":"ハハハ、ところで……あのレイ先輩という方とはまだ連絡がつかないんですか？","ENG":"Hah hah, by the way... Are you still having trouble getting in touch with this Ray person?","TWN":"哈哈，可是……現在還聯繫不到叫雷伊的那個前輩嗎？"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어? 으, 응. 돌아는 왔다는데 전화를 안 받네.","JPN":"あ、うん。帰ってきたらしいけど、電話に出ないね。","ENG":"Huh? Y-yeah. I heard he's back, but he won't take my calls.","TWN":"啊？嗯，據說回來了，但他完全不接我的電話。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좀 이상한 말이지만 네르비에와 싸울 때 분명 선배를 봤던 것 같거든......","JPN":"ちょっとおかしな話だけど、ネルヴィエと戦う時に確かに先輩を見た覚えがあるのに……","ENG":"I know this sounds strange, but I could have sworn I saw him when I was fighting Nervier...","TWN":"可能聽起來有些奇怪，但我在與尼爾比耶戰鬥的時候明明記得見到過前輩……"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데...... 그 때 상황이 정확히 기억이 안 나.","JPN":"でも……あの時の状況を正確に思い出せなくて。","ENG":"But... I can't exactly recall what happened then.","TWN":"不過……就是想不起來當時的情況。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다음에 등교하면 본인에게 직접 물어 보려고.","JPN":"今度登校したら本人に直接聞いてみる。","ENG":"I figured I'll ask him in person when I return to school.","TWN":"我打算下次去學校的時候直接去問問他本人。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇군요......","JPN":"そうなんですね……","ENG":"I see...","TWN":"這樣啊……"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"수송기가 도착했다, 신입. 잡담은 그만하고 얼른 탑승이나 해.","JPN":"輸送機が到着したぞ、新人。無駄話はいい加減にしてさっさと搭乗しろ。","ENG":"The dropship is here, rookie. Enough chatter. Hop aboard.","TWN":"運輸機到了。新人，閒聊就到此為止，趕快乘機吧。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 알았어! 소대장! 지금 갈게!","JPN":"わ、わかった、小隊長！　今行く！","ENG":"O-okay, Commander! I'll be right there!","TWN":"知、知道了！小隊長！馬上就過去！"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어라? 오늘은 스승님과 같이 퇴근하시나요?","JPN":"あれ？　今日は師匠と一緒に退勤ですか？","ENG":"Hmm? Are you leaving with the Master today?","TWN":"咦？今天你跟師父一起下班嗎？"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응. 내일은 비번이라 언니 병문안을 가기로 했거든.","JPN":"うん。明日は休みだから姉さんのお見舞いに行く。","ENG":"Yeah. I'm off tomorrow, so I'm going to visit my sister at the hospital.","TWN":"嗯。因為明天休息，所以決定去醫院看看姐姐。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"소대장이 중간에 병원에서 내려 준대.","JPN":"小隊長が帰り道の途中だから、病院で降ろしてくれるって。","ENG":"Commander will drop me off at the hospital.","TWN":"小隊長說會送我到醫院。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇군요.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"오늘 왠지 스승님 표정이 좋지 않던데 조심해서 들어가세요.","JPN":"今日の師匠、なんだか浮かない表情だったので気をつけてくださいね。","ENG":"Do be careful though. Master doesn't seem to be in a good mood today.","TWN":"今天看老師的表情不是很好，你要小心些。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배도 조심해서 들어가. 다음 주에 지각하지 말고.","JPN":"先輩も気をつけて帰ってね。来週遅刻しないでよ。","ENG":"You take care too. Don't be late next week.","TWN":"前輩也注意安全，記得下周不要遲到。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하. 물론이죠.","JPN":"ハハ、もちろんです。","ENG":"Hah hah. Of course.","TWN":"哈哈，當然了。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"자, 그럼...... 슬슬 나와주실까요?","JPN":"さて、そろそろ……出てきてもらえませんか？","ENG":"Well, then... Will you show yourself now?","TWN":"好了……現在可以出來了吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_6100014","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"오래 기다리게 해서 죄송하네요. 레이 선배라고 했던가요?","JPN":"長らくお待たせして申し訳ございません。レイ先輩、でしたね？","ENG":"Sorry to keep you waiting for so long. You are Ray, right?","TWN":"真抱歉讓你久等了，你是叫雷伊前輩吧？"},"stage":{"bg":"MAINSTREAM_6100014","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서 제게 무슨 볼일이신지, 한 번 들어 볼까요?","JPN":"それで僕に何の用なのか、聞いてもいいでしょうか。","ENG":"So, what was it that you wanted to discuss with me?","TWN":"那你找我有什麼事，我來聽聽看？"},"stage":{"bg":"MAINSTREAM_6100014","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"미안해......","JPN":"ごめん……","ENG":"I’m sorry...","TWN":"對不起……"},"stage":{"bg":"MAINSTREAM_6100015","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"나도...... 이러고 싶지 않았어.","JPN":"僕も……こんなことはしたくなかった。","ENG":"I... didn't want to do this...","TWN":"我也……不願意這樣。"},"stage":{"bg":"MAINSTREAM_6100015","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네? 무슨 말씀이시죠?","JPN":"うん？　どういうことですか？","ENG":"Sorry? What are you talking about?","TWN":"啊？你在說什麼？"},"stage":{"bg":"MAINSTREAM_6100015","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"하지만...... 하지만 나도 더 이상은......","JPN":"でも……でも、僕もこれ以上……","ENG":"But... But I can no longer...","TWN":"但是...... 但是我也沒辦法……"},"stage":{"bg":"MAINSTREAM_6100015","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"더 이상은 거절할 수가 없어......","JPN":"これ以上は断れない……","ENG":"I can no longer resist...","TWN":"沒辦法再拒絕……"},"stage":{"bg":"MAINSTREAM_6100015","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"난, 맹세를 지켜야 하니까.","JPN":"僕は、誓いを果たさなければならないから。","ENG":"I must honor my oath.","TWN":"因為我要遵守我的誓言。"},"stage":{"bg":"MAINSTREAM_6100015","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"대체 무슨 소릴......?","JPN":"いったい何の話を……？","ENG":"What on earth are you talking—","TWN":"你到底在說什麼……？"},"stage":{"bg":"MAINSTREAM_6100015","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_6100016","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};